import '../../domain/entities/report.dart'; extension ReportReasonLocalization on ReportReason{String get title{switch(this){case ReportReason.scam:return 'Scam / Fraud'; case ReportReason.fakeProduct:return 'Fake Product'; case ReportReason.inappropriateContent:return 'Inappropriate Content'; case ReportReason.harassment:return 'Harassment'; case ReportReason.spam:return 'Spam'; case ReportReason.prohibitedItem:return 'Prohibited Item'; case ReportReason.wrongCategory:return 'Wrong Category'; case ReportReason.other:return 'Other';}} String get description=>'Report this issue to moderators.';}
